const body = $json.body && typeof $json.body === 'object' && !Array.isArray($json.body) ? $json.body : {};
const payload = Object.keys(body).length ? body : $json;
const transcriptSourceUrl = String(payload.transcript_source_url || payload.url || '').trim();

const parseOptionalBoolean = (...values) => {
  for (const value of values) {
    if (value === true || value === false) {
      return value;
    }
    if (typeof value === 'number' && Number.isFinite(value)) {
      if (value === 1) {
        return true;
      }
      if (value === 0) {
        return false;
      }
    }
    if (typeof value === 'string') {
      const normalized = value.trim().toLowerCase();
      if (!normalized) {
        continue;
      }
      if (['true', '1', 'yes', 'y', 'on'].includes(normalized)) {
        return true;
      }
      if (['false', '0', 'no', 'n', 'off'].includes(normalized)) {
        return false;
      }
    }
  }
  return null;
};

if (!transcriptSourceUrl) {
  throw new Error('url is required for 06_manual_media_submit');
}

const match = transcriptSourceUrl.match(/^(https?):\/\/([^\/?#]+)(\/[^?#]*)?/i);
if (!match) {
  throw new Error('Invalid media URL: expected an absolute http/https URL');
}

const host = String(match[2] || '').replace(/:\d+$/, '').replace(/^www\./i, '').toLowerCase();
const pathname = String(match[3] || '/');
const isYouTube = /(^|\.)(youtube\.com|youtu\.be)$/.test(host);
const isXiaoyuzhouEpisode = host === 'xiaoyuzhoufm.com' && /^\/episode\//i.test(pathname);
const isBilibiliVideo = /(^|\.)bilibili\.com$/.test(host) && /^\/video\//i.test(pathname);
const isDedaoShare = host === 'd.dedao.cn'
  || (host === 'dedao.cn' && /^\/share\/course\/article(?:\/|$)/i.test(pathname));
const isAudioFile = /\.(mp3|m4a|aac|wav|ogg)(?:$|[?#])/i.test(transcriptSourceUrl);
const isVideoFile = /\.(mp4|mov|m4v|webm|mkv)(?:$|[?#])/i.test(transcriptSourceUrl);
const supported = isYouTube || isXiaoyuzhouEpisode || isBilibiliVideo || isDedaoShare || isAudioFile || isVideoFile;

if (!supported) {
  throw new Error('06_manual_media_submit only accepts media URLs such as YouTube, Xiaoyuzhou episodes, Bilibili videos, Dedao share pages, or direct audio/video files');
}

const inferredSourceType = String(payload.source_type || '').trim()
  || (isXiaoyuzhouEpisode || isAudioFile ? 'podcast' : 'transcript');
const inferredMediaType = String(payload.media_type || '').trim()
  || (isXiaoyuzhouEpisode || isAudioFile ? 'audio' : 'video');
const defaultSourceName = isYouTube
  ? 'YouTube manual submit'
  : isXiaoyuzhouEpisode
    ? 'Xiaoyuzhou manual submit'
    : isBilibiliVideo
      ? 'Bilibili manual submit'
      : isDedaoShare
        ? 'Dedao manual submit'
        : host || 'manual media submit';
const pollIntervalMs = Number(payload.poll_interval_ms || payload.transcriptPollIntervalMs || 0);
const maxPolls = Number(payload.max_polls || payload.transcriptMaxPolls || 0);
const explicitSpeakerRecognition = parseOptionalBoolean(
  payload.use_speaker_recognition,
  payload.useSpeakerRecognition
);
const requestedTags = Array.isArray(payload.extra_tags)
  ? payload.extra_tags
  : Array.isArray(payload.tags)
    ? payload.tags
    : [];
const extraTags = [...new Set([
  'manual-submit',
  ...(isDedaoShare ? ['dedao'] : []),
  ...requestedTags.map((tag) => String(tag).trim())
].filter(Boolean))];
const manualSubmissionId = Number(payload.manual_submission_id || payload.manualSubmissionId || 0);
const collectorCallbackUrl = String(payload.collector_callback_url || payload.collectorCallbackUrl || '').trim();

return {
  json: {
    transcript_source_url: transcriptSourceUrl,
    canonical_url: String(payload.canonical_url || transcriptSourceUrl).trim(),
    source_name: String(payload.source_name || payload.sourceName || defaultSourceName).trim() || defaultSourceName,
    source_type: inferredSourceType,
    media_type: inferredMediaType,
    title: String(payload.title || '').trim(),
    author: String(payload.author || '').trim(),
    description: String(payload.description || '').trim(),
    published_at: payload.published_at || new Date().toISOString(),
    obsidian_inbox_dir: String(payload.obsidian_inbox_dir || payload.obsidianInboxDir || $env.OBSIDIAN_INBOX_DIR || '00_Inbox').trim() || '00_Inbox',
    ...(explicitSpeakerRecognition == null ? {} : { use_speaker_recognition: explicitSpeakerRecognition }),
    ...(Number.isFinite(manualSubmissionId) && manualSubmissionId > 0 ? { manual_submission_id: manualSubmissionId } : {}),
    ...(collectorCallbackUrl ? { collector_callback_url: collectorCallbackUrl } : {}),
    download_url: String(payload.download_url || '').trim(),
    extra_tags: extraTags,
    ...(Number.isFinite(pollIntervalMs) && pollIntervalMs > 0 ? { poll_interval_ms: pollIntervalMs } : {}),
    ...(Number.isFinite(maxPolls) && maxPolls > 0 ? { max_polls: maxPolls } : {}),
    original_request: {
      headers: $json.headers ?? {},
      params: $json.params ?? {},
      query: $json.query ?? {}
    },
    original_item: payload
  }
};

const metadata = $input.item.json && typeof $input.item.json === 'object' ? $input.item.json : {};

if (typeof metadata.error === 'string' && metadata.error.trim()) {
  return {
    json: {
      ok: false,
      stage: '04_video_transcript_ingest',
      error: metadata.error.trim(),
      should_write_to_vault: false,
      vault_write_status: 'error',
      vault_write: 'error',
      debug_input: $('Normalize Manual Media Request').item.json ?? {}
    }
  };
}

return {
  json: {
    ok: true,
    workflow_label: 'manual-media-submit',
    ...metadata
  }
};

